const inputData = $input.first().json;
const inputBinary = $input.first().binary;
// Un Script 1 exitoso devuelve el file object del paso1 con id + name.
// Si fallo (throw capturado), no hay id -> es error.
const hasFileId = !!(inputData && inputData.id);
const errMsg = (inputData && (inputData.error?.message || inputData.error || inputData.message)) || null;
const wasError = !hasFileId;
return [{
  json: {
    script1_status: wasError ? 'error' : 'ok',
    script1_paso1_id: inputData?.id || null,
    script1_paso1_name: inputData?.name || null,
    script1_error: wasError ? (errMsg ? String(errMsg).substring(0, 400) : 'Script 1 no genero el archivo paso1') : null,
    script1_raw: JSON.stringify(inputData).substring(0, 500),
  },
  binary: inputBinary,
}];

const inputData = $input.first().json;
const hasFileId = !!(inputData && inputData.id);
const errMsg = (inputData && (inputData.error?.message || inputData.error || inputData.message)) || null;
const wasError = !hasFileId;
const prev = $('Capturar resultado 1').first().json;
return [{
  json: {
    ...prev,
    script2_status: wasError ? 'error' : 'ok',
    script2_paso2_id: inputData?.id || null,
    script2_paso2_name: inputData?.name || null,
    script2_error: wasError ? (errMsg ? String(errMsg).substring(0, 400) : 'Script 2 no genero paso2') : null,
    script2_raw: JSON.stringify(inputData).substring(0, 500),
  }
}];

const inputData = $input.first().json;
const hasFileId = !!(inputData && inputData.id);
const errMsg = (inputData && (inputData.error?.message || inputData.error || inputData.message)) || null;
const wasError = !hasFileId;
const prev = $('Capturar resultado 2').first().json;
const allOk = (prev.script1_status === 'ok' && prev.script2_status === 'ok' && !wasError);
return [{
  json: {
    ...prev,
    script3_status: wasError ? 'error' : 'ok',
    script3_paso3_id: inputData?.id || null,
    script3_paso3_name: inputData?.name || null,
    script3_error: wasError ? (errMsg ? String(errMsg).substring(0, 400) : 'Script 3 no genero paso3') : null,
    script3_raw: JSON.stringify(inputData).substring(0, 500),
    master_status: allOk ? 'OK_TODOS_LOS_SCRIPTS' : 'ERROR_EN_ALGUN_SCRIPT',
    timestamp: new Date().toISOString(),
    resumen: allOk
      ? `Procesamiento completo OK. paso1=${prev.script1_paso1_name}, paso2=${prev.script2_paso2_name}, paso3=${inputData?.name}`
      : `Falla detectada. script1=${prev.script1_status}, script2=${prev.script2_status}, script3=${wasError ? 'error' : 'ok'}`,
  }
}];

// Anti-doble disparo del MASTER usando staticData
const LOCK_MIN = 4;
const staticData = $getWorkflowStaticData('global');
const ahora = Date.now();
const ultimoDisparo = staticData.ultimoDisparoMASTER || 0;
const minutosDesde = ultimoDisparo > 0 ? (ahora - ultimoDisparo) / 1000 / 60 : 999;
const esDoble = ultimoDisparo > 0 && minutosDesde < LOCK_MIN;

if (esDoble) {
  return [{
    json: {
      es_doble: true,
      minutos_desde_ultimo: Math.round(minutosDesde * 10) / 10,
      lock_min: LOCK_MIN,
      mensaje: 'MASTER ya disparado hace ' + Math.round(minutosDesde * 10) / 10 + ' min. Lock activo hasta ' + LOCK_MIN + ' min. Saltado.',
      timestamp_ultimo_disparo: new Date(ultimoDisparo).toISOString(),
      timestamp_actual: new Date(ahora).toISOString()
    }
  }];
}

// Pasa el check - actualizar timestamp
staticData.ultimoDisparoMASTER = ahora;

return [{
  json: {
    es_doble: false,
    mensaje: 'OK proceder con MASTER',
    timestamp_disparo: new Date(ahora).toISOString(),
    minutos_desde_ultimo: minutosDesde === 999 ? 'primera_ejecucion' : Math.round(minutosDesde * 10) / 10
  }
}];

// Log a Bitacora cuando se evita un doble disparo
const data = $('Check Anti-Doble Disparo').first().json;
return [{
  json: {
    workflow: 'master_orquestador',
    accion: 'anti_doble_disparo_bloqueado',
    detalle: JSON.stringify({
      minutos_desde_ultimo: data.minutos_desde_ultimo,
      lock_min: data.lock_min,
      timestamp_ultimo_disparo: data.timestamp_ultimo_disparo
    }),
    timestamp: new Date().toISOString()
  }
}];

