// Pasa las fechas elegidas (control manual) desde el body del webhook -> Script 1.
// Si no vienen fechas, manda array vacio y Script 1 usa el modo AUTO (filtro por Yopago).
const body = ($('Webhook MASTER').first().json.body) || {};
let fechas = [];
if (Array.isArray(body.fechas_a_procesar)) {
  fechas = body.fechas_a_procesar.map(f => String(f).trim()).filter(Boolean);
}
return [{ json: { fechas_a_procesar: fechas, _historial_pre: $input.first().json } }];
